<template><div class="toolbar-block"><div class="panel-title">道路类型</div><div v-for="r in roadType.roadTypes" :key="r.id" class="road-card" :class="{active:r.id===roadType.selectedRoadTypeId}" @click="roadType.selectedRoadTypeId=r.id"><div class="row"><b>{{ r.name }}</b><span class="small">{{ r.speedLimit }}km/h</span></div><div class="small">车道 {{ r.forwardLaneCount }} + {{ r.backwardLaneCount }} · 宽度 {{ getRoadTypeWidth(r).toFixed(1) }}m</div><div class="small">{{ r.hasSidewalk?'人行道':'' }} {{ r.hasGreenBelt?'绿化带':'' }} {{ r.hasMedian?'中央隔离':'' }}</div></div></div></template>
<script setup lang="ts">import { useRoadTypeStore } from '../stores/roadTypeStore'; import { getRoadTypeWidth } from '../types/roadType'; const roadType=useRoadTypeStore()</script>
